class Solution(object):
    def maximumPoints(self, enemyEnergies, currentEnergy):
        min_e = min(enemyEnergies)
        # If we can't even defeat the weakest enemy, return 0
        if currentEnergy < min_e:
            return 0

        # Strategy: absorb all enemies except the weakest, then farm the weakest
        total_energy = currentEnergy + sum(enemyEnergies) - min_e
        # We use the weakest enemy to gain points: each defeat costs min_e energy
        return total_energy // min_e
